class CodebasePathwayTracerMetadata(AgentMetadataBase):
    agent_id: str = "codebase-pathway-tracer"
    name: str = "codebase-pathway-tracer"
    description: str = "MUST BE USED to trace possible logical pathways through codebases. Analyzes code structure, data flow, execution paths, dependency relationships, and architectural patterns to map comprehensive logical pathways. Passes structured pathway data to graph writer systems for visualization and analysis."
    type: str = "TASK"
